public class ListNode {
    int val;
    ListNode next;
    ListNode(int x) { val = x; }
}

public int numComponents(ListNode head, int[] nums) {
    Set<Integer> numSet = new HashSet<>();
    for (int num : nums) {
        numSet.add(num);
    }

    int result = 0;
    boolean connected = false;

    while (head != null) {
        if (numSet.contains(head.val)) {
            if (!connected) {
                connected = true;
                result++;
            }
        } else {
            connected = false;
        }
        head = head.next;
    }

    return result;
}
```


